3973	// terminal state (FEAT-004 §Queue Semantics For Epics). Returns the count of
3974	// epics closed. Idempotent: a second call closes nothing new.
3975	func (w *ExecuteBeadWorker) runEpicClosureCascade(ctx context.Context, emit func(string, map[string]any)) (int, error) {
3976		closer, ok := w.Store.(epicCloser)
3977		if !ok {
3978			return 0, nil
3979		}
3980		candidates, err := closer.EpicClosureCandidates(ctx)
3981		if err != nil || len(candidates) == 0 {
3982			return 0, err
3983		}
3984		closed := 0
3985		for _, epic := range candidates {
3986			if err := closer.Close(ctx, epic.ID); err == nil {
3987				closed++
3988				emit("loop.epic_auto_closed", map[string]any{
3989					"bead_id": epic.ID,
3990					"title":   epic.Title,
3991				})
3992			}
3993		}
3994		return closed, nil
3995	}
