				candidateID,
				err,
			)
		}
		emit("loop.operator_attention", map[string]any{
			"reason":       "durable_audit_commit_failed",
			"bead_id":      candidateID,
			"project_root": projectRoot,
			"dirty_paths":  dirtyPaths,
			"message":      result.OperatorAttention.Message,
			"detail":       strings.TrimSpace(err.Error()),
