	if strings.TrimSpace(report.Provider) != "" {
		return false
	}
	combined := strings.ToLower(strings.Join([]string{
		report.Detail,
		report.Error,
		report.Stderr,
	}, "\n"))
	return isServerTransportFailureText(combined)
}

